+			var limit *int
+			if v, ok := args["offset"]; ok {
+				if n, ok := v.(float64); ok {
+					ni := int(n)
+					offset = &ni
+				}
+			}
+			if v, ok := args["limit"]; ok {
+				if n, ok := v.(float64); ok {
+					ni := int(n)
+					limit = &ni
+				}
+			}
+			return env.ReadFile(path, offset, limit)
+		},
+	}); err != nil {
+		return err
