+			var b strings.Builder
+			for _, p := range paths {
+				p = strings.TrimSpace(p)
+				if p == "" {
+					continue
+				}
+				b.WriteString("----- BEGIN " + p + " -----\n")
+				txt, err := env.ReadFile(p, offset, limit)
+				if err != nil {
+					b.WriteString("[ERROR] " + err.Error() + "\n")
