+		},
+	})
+
+	// shell
+		if err := reg.Register(RegisteredTool{
+			Definition: defShell(),
+			Exec: func(ctx context.Context, env ExecutionEnvironment, args map[string]any) (any, error) {
+				cmd := fmt.Sprint(args["command"])
