+	_ = reg.Register(RegisteredTool{
+		Definition: defCloseAgent(),
+		Exec: func(ctx context.Context, env ExecutionEnvironment, args map[string]any) (any, error) {
+			_ = env
+			return s.closeAgent(fmt.Sprint(args["agent_id"]))
+		},
+	})
+
+	return nil
+}

