+func TestClient_Stream_MiddlewareChainOrder(t *testing.T) {
+	c := NewClient()
+	a := &streamAdapter{name: "openai"}
+	c.Register(a)
+
+	var mu sync.Mutex
+	var order []string
+	log := func(s string) {
+		mu.Lock()
+		defer mu.Unlock()
+		order = append(order, s)
+	}
