+package llm
+
+import (
+	"errors"
+	"fmt"
+	"net/http"
+	"strconv"
+	"strings"
+	"time"
+)
+
+// Error is the unified error interface returned by provider adapters and the client.
+type Error interface {
+	error
+	Provider() string
+	StatusCode() int
+	Retryable() bool
+	RetryAfter() *time.Duration
+}
+
+type ConfigurationError struct {
+	Message string
+}
+
+func (e *ConfigurationError) Error() string {
+	return "configuration error: " + strings.TrimSpace(e.Message)
+}
+func (e *ConfigurationError) Provider() string           { return "" }
+func (e *ConfigurationError) StatusCode() int            { return 0 }
+func (e *ConfigurationError) Retryable() bool            { return false }
+func (e *ConfigurationError) RetryAfter() *time.Duration { return nil }
+
+type httpErrorBase struct {
+	provider    string
+	statusCode  int
+	message     string
+	retryable   bool
+	retryAfter  *time.Duration
+	rawResponse any
+}
+
+func (e *httpErrorBase) Error() string {
+	msg := strings.TrimSpace(e.message)
+	if msg == "" {
+		msg = "request failed"
+	}
+	return fmt.Sprintf("%s error (status=%d): %s", e.provider, e.statusCode, msg)
+}
+func (e *httpErrorBase) Provider() string           { return e.provider }
+func (e *httpErrorBase) StatusCode() int            { return e.statusCode }
+func (e *httpErrorBase) Retryable() bool            { return e.retryable }
+func (e *httpErrorBase) RetryAfter() *time.Duration { return e.retryAfter }
+
+type InvalidRequestError struct{ httpErrorBase }
+type AuthenticationError struct{ httpErrorBase }
+type AccessDeniedError struct{ httpErrorBase }
+type NotFoundError struct{ httpErrorBase }
+type RequestTimeoutError struct{ httpErrorBase }
+type ContextLengthError struct{ httpErrorBase }
+type RateLimitError struct{ httpErrorBase }
+type ServerError struct{ httpErrorBase }
+type UnknownHTTPError struct{ httpErrorBase }
+
+func ErrorFromHTTPStatus(provider string, statusCode int, message string, raw any, retryAfter *time.Duration) error {
+	base := httpErrorBase{
+		provider:    strings.TrimSpace(provider),
+		statusCode:  statusCode,
+		message:     message,
+		retryAfter:  retryAfter,
+		rawResponse: raw,
+	}
+	switch statusCode {
+	case 400, 422:
+		base.retryable = false
+		return &InvalidRequestError{base}
+	case 401:
+		base.retryable = false
+		return &AuthenticationError{base}
+	case 403:
+		base.retryable = false
+		return &AccessDeniedError{base}
+	case 404:
+		base.retryable = false
+		return &NotFoundError{base}
+	case 408:
+		base.retryable = true
+		return &RequestTimeoutError{base}
+	case 413:
+		base.retryable = false
+		return &ContextLengthError{base}
+	case 429:
+		base.retryable = true
+		return &RateLimitError{base}
+	case 500, 502, 503, 504:
+		base.retryable = true
+		return &ServerError{base}
+	default:
+		// Spec: unknown errors default to retryable.
+		base.retryable = true
+		return &UnknownHTTPError{base}
+	}
+}
+
+// NewRequestTimeoutError constructs a non-HTTP timeout error (e.g., context deadline
+// exceeded) that matches the unified error hierarchy. These timeouts are not retried
+// by default (spec).
+func NewRequestTimeoutError(provider string, message string) error {
+	base := httpErrorBase{
+		provider:   strings.TrimSpace(provider),
+		statusCode: 0,
+		message:    message,
+		retryable:  false,
+	}
+	return &RequestTimeoutError{base}
+}
+
+// ParseRetryAfter parses the Retry-After header value.
+// Supported forms:
+// - integer seconds
+// - HTTP-date (RFC 7231)
+func ParseRetryAfter(v string, now time.Time) *time.Duration {
+	v = strings.TrimSpace(v)
+	if v == "" {
+		return nil
+	}
+	if secs, err := strconv.Atoi(v); err == nil && secs >= 0 {
+		d := time.Duration(secs) * time.Second
+		return &d
+	}
+	if t, err := http.ParseTime(v); err == nil {
+		d := t.Sub(now)
+		if d < 0 {
+			d = 0
+		}
+		return &d
+	}
+	return nil
+}
+
+func IsAuthenticationError(err error) bool {
+	var e *AuthenticationError
+	return errors.As(err, &e)
+}

